def write_csv(path: str, data: dict) -> None:
    """Write a food dictionary to a CSV file with the standard COLUMNS header."""
    with open(path, "w", newline="", encoding="utf-8") as f:
        writer = csv.writer(f)
        writer.writerow(COLUMNS)
        for name, vals in data.items():
            (category, cal, protein, carbs, fiber, fat, sugar, iron, ca, mg, k, na, zn,
             vA, b12, vC, vD, vE, vK, folate, o3, o6, serving, cost, avail) = vals
            row = [
                name, category, cal, protein, carbs, fiber, fat, sugar, iron, ca, mg,
                k, na, zn, vA, b12, vC, vD, vE, vK, folate, o3, o6, serving, cost, avail,
                f"assets/{name.lower().replace(' ', '_').replace('(', '').replace(')', '').replace(',', '')}.png",
                f"{name} - {category} food item with per-serving nutrition data.",
                "Curated dataset (USDA/typical nutrition references)"
            ]
            writer.writerow(row)


if __name__ == "__main__":
    base = os.path.dirname(os.path.abspath(__file__))
    write_csv(os.path.join(base, "veg_foods.csv"), VEG_FOODS)
    write_csv(os.path.join(base, "nonveg_foods.csv"), NONVEG_FOODS)
    print(f"Wrote {len(VEG_FOODS)} vegetarian foods and {len(NONVEG_FOODS)} non-vegetarian foods.")
